import { intervalUp, intervalUpPitch, } from "./intervals.js";
import { octaveUp } from "./pitch.js";
export const chordIntervalSpecs = {
    major: ["maj3", "p5"],
    minor: ["min3", "p5"],
    dim: ["min3", "dim5"],
    dom7: ["maj3", "p5", "min7"],
    halfDim7: ["min3", "dim5", "min7"],
    fullDim7: ["min3", "dim5", "dim7"],
};
/**
 * Creates a chord of pitch classes
 * @param chordType
 * @param root
 * @returns A chord
 */
export function makeChord(chordType, root) {
    switch (chordType) {
        case "major":
            return {
                chordType: chordType,
                root: root,
                third: intervalUp(root, "maj3"),
                fifth: intervalUp(root, "p5"),
                seventh: undefined,
            };
        case "minor":
            return {
                chordType: chordType,
                root: root,
                third: intervalUp(root, "min3"),
                fifth: intervalUp(root, "p5"),
                seventh: undefined,
            };
        case "dom7":
            return {
                chordType: chordType,
                root: root,
                third: intervalUp(root, "maj3"),
                fifth: intervalUp(root, "p5"),
                seventh: intervalUp(root, "min7"),
            };
        case "dim":
            return {
                chordType: chordType,
                root: root,
                third: intervalUp(root, "min3"),
                fifth: intervalUp(root, "dim5"),
                seventh: undefined,
            };
        case "halfDim7":
            return {
                chordType: chordType,
                root: root,
                third: intervalUp(root, "min3"),
                fifth: intervalUp(root, "dim5"),
                seventh: intervalUp(root, "min7"),
            };
        case "fullDim7":
            return {
                chordType: chordType,
                root: root,
                third: intervalUp(root, "min3"),
                fifth: intervalUp(root, "dim5"),
                seventh: intervalUp(root, "dim7"),
            };
    }
}
export function secondaryDominant(chord) {
    if (["dim", "halfDim7", "fullDim7"].includes(chord.chordType))
        return [chord];
    const root = intervalUp(chord.root, "p5");
    return [makeChord("dom7", root), chord];
}
export function voiceChord(chord, octave, inversion = "root") {
    const [thirdInt, fifthInt, seventhInt] = chordIntervalSpecs[chord.chordType];
    const root = { pitchClass: chord.root, octave: octave };
    const third = intervalUpPitch(root, thirdInt);
    const fifth = intervalUpPitch(root, fifthInt);
    const seventh = chord.seventh
        ? intervalUpPitch(root, seventhInt)
        : undefined;
    switch (inversion) {
        case "root":
            return {
                chord: chord,
                inversion: inversion,
                notes: [root, third, fifth, ...(seventh ? [seventh] : [])],
            };
        case "first":
            return {
                chord: chord,
                inversion: inversion,
                notes: [third, fifth, ...(seventh ? [seventh] : []), octaveUp(root)],
            };
        case "second":
            return {
                chord: chord,
                inversion: inversion,
                notes: [
                    fifth,
                    ...(seventh ? [seventh] : []),
                    octaveUp(root),
                    octaveUp(third),
                ],
            };
        case "third":
            if (!seventh) {
                return undefined;
            }
            return {
                chord: chord,
                inversion: inversion,
                notes: [seventh, octaveUp(root), octaveUp(third), octaveUp(fifth)],
            };
    }
}
