import { modeChords, } from "./romanNumerals.js";
export const plagalCadence = ["I", "IV", "I"];
export const deceptiveCadence = ["V", "VI"];
export const authenticCadence = ["I"];
export const allCadences = [
    authenticCadence,
    plagalCadence,
    deceptiveCadence,
];
export function insertCadence(cadence, mode) {
    const result = [];
    for (const c of cadence) {
        result.push({
            degree: c,
            chordType: modeChords[mode][c][0],
        });
    }
    return result;
}
