import { clampOctave } from "./intervals.js";
/**
 * Bumps up one octave, clamped at 7
 * @param pitch
 * @returns
 */
export function octaveUp(pitch) {
    return {
        pitchClass: pitch.pitchClass,
        octave: clampOctave(pitch.octave + 1),
    };
}
/**
 * Bumps down one octave, clamped at 0
 * @param pitch
 * @returns
 */
export function octaveDown(pitch) {
    return {
        pitchClass: pitch.pitchClass,
        octave: clampOctave(pitch.octave - 1),
    };
}
